export default function Input({ label, ...props }) {
  return (
    <div style={{ marginBottom: "10px" }}>
      <label style={{ display: "block", marginBottom: "5px" }}>{label}</label>
      <input {...props} style={{ padding: "8px", width: "100%" }} />
    </div>
  );
}
